UPDATE paragraphs SET transcript = 'welkom bij de uitleg van baast of drie en die gaat over metamorfose voordat ik begin met uitleg is het goed om te weten dat vanaf hier de volgorde van de baas stoffen per boek een beetje kan verschillen kijk even goed naar de titel want de inhoud komt namelijk er wel overheen dan beginnen we met de volgende zaken we gaan het hebben over wat een metamorfose of een gedaanteverwisseling is dat zijn twee woorden voor hetzelfde in feite dan gaan we kijken hoe de levenscyclus van een kikker verloot en we gaan ook kijken naar de levenscyclus van een vlinder dan beginnen we met het begrip metamorfose en dat wil zeggen dat de leefwijze en lichaamsbouw van een organisme veranderd in de loop van het leven nou dat kun je geweldig zien aan vlinder een vlinder begint zijn leven eigenlijk als een eitje en het het eind je komt een rupsje dat een rups je dat eet zich helemaal volgen op een gegeven moment houdt het rupsen onze genen cocon en in die cocon vind de metamorfose plaats en uiteindelijk komt er uit de cocon geen rups maar volledig ontwikkelde vlinder dus er heeft dan dus een metamorfose plaats gevonden en daarbij zie je dus ook dat hele lichaamsbouw veranderd is zij die rups lijkt op geen enkele manier ze ongeveer meer op die vlinder en de leefwijze is ook veranderd waar die rust bijvoorbeeld niet kan vliegen kan die viel in dat wel bedenk je ook dat een vlinder zich kan voortplanten en een groots niet dus zo zie je dat er allerlei veranderingen zijn opgetreden in dus te leefwijze en de lichaamsbouw van deze vlinder dat zie je bij kikkers ook kikkers beginnen hun leven als kikkerdril dat zijn bevruchten kikker eitjes in feite en daar komen uiteindelijk kikkervisjes uit die kikkervisjes die hebben hier aan de buitenkant cue we zitten dus hebben uitwendig cue we leven dus in het water ze kunnen ademhalen met behulp van de kieuwen en ze kunnen ademhalen met behulp van hun huid vervolgens ontwikkelen zich verder en dan zie je dat het steeds meer een beetje richtingen kikker gaat je ziet al hier dat de cue we al verdwenen zijn die zitten aan de binnenkant hebben ze nu inwendige cue we nu ziet ook dat hier al pootjes aan het ontwikkelen zijn en uiteindelijk ontwikkeld dus zo''n kikkervisjes zich tot een kikker en als je uiteindelijk kijkt naar die kikker dan zie je dus dat hij geen cue heeft ook niet inwendig heeft nou longen hij ziet dat hele poten zijn ontwikkeld het staartje is weg en een kikker kan dus ook boven water overleven waar een kikkervisje dat nog niet kon en uw kikker haalt over gezogen adem met de huid dus kikker haalt adem met de huid en de longen waar een kikkervisje dat deed met cue we en de huid dus daar zie je ook dat de hele leefwijze dan dus verander dat deze kikker dus boven water kan zijn en dus uiteindelijk ook dat deze kikker zich een vel kan voortplanten waar dus die kleine kikkervisjes nog helemaal niet geslachtsrijp zijn dit was de uitleg over metamorfose hier nog de samenvatting heel veel succes met oefenen en tot de volgende' WHERE id = '1-7';